def gen(rng, size):
    n = max(1, min(size, 100000))
    differences = [rng.randint(-1000, 1000) for _ in range(n)]
    lower = rng.randint(-100000, 0)
    upper = lower + rng.randint(0, 200000)
    if upper > 100000:
        upper = 100000
    if upper < lower:
        upper = lower
    return [differences, lower, upper]

