class Solution:
    def numberOfArrays(self, differences, lower, upper):
        count = 0
        for start in range(lower, upper + 1):
            val = start
            ok = True
            for d in differences:
                val += d
                if val < lower or val > upper:
                    ok = False
                    break
            if ok:
                count += 1
        return count

