class Solution:
    def numberOfArrays(self, differences, lower, upper):
        prefix = 0
        lo = hi = 0
        for d in differences:
            prefix += d
            if prefix < lo:
                lo = prefix
            if prefix > hi:
                hi = prefix
        span = hi - lo
        count = (upper - lower + 1) - span
        return count if count > 0 else 0

