var numberOfArrays = function(differences, lower, upper) {
    let prefix = 0, lo = 0, hi = 0;
    for (const d of differences) {
        prefix += d;
        if (prefix < lo) lo = prefix;
        if (prefix > hi) hi = prefix;
    }
    const span = hi - lo;
    const count = (upper - lower + 1) - span;
    return count > 0 ? count : 0;
